import React from 'react'
import { Link } from 'react-router-dom'

export default function Header() {
  return (
    <div className='text-2xl flex gap-4'>
      
      <Link to="/">home</Link>
      <Link to="/about">about</Link>
      <Link to="/product">product</Link>
    </div>
  )
}
